mapper.select:
SELECT lt.login_type_id, lt.login_type_name, lt.login_type_code, lt.login_type_description, lt.login_type_config, lt.is_active, lt.sort_order, lt.enterprise_id, lt.creator_id, lt.create_time, lt.update_by, lt.update_time, COUNT(s.script_id) AS script_count FROM datacloud_login_type lt LEFT JOIN datacloud_script s ON lt.login_type_id = s.login_type_id WHERE lt.enterprise_id = #{query.enterpriseId}
AND lt.login_type_name LIKE CONCAT('%', #{query.loginTypeName}, '%')
AND lt.login_type_code LIKE CONCAT('%', #{query.loginTypeCode}, '%')
AND lt.is_active = #{query.isActive}
GROUP BY lt.login_type_id ORDER BY lt.sort_order ASC, lt.create_time DESC

SELECT COUNT(*)
FROM datacloud_login_type
WHERE login_type_code = #{loginTypeCode}
AND enterprise_id = #{enterpriseId}

    AND login_type_id != #{excludeId}

SELECT COUNT(*)
FROM datacloud_script
WHERE login_type_id = #{loginTypeId}

